/**
 * CarIllustration
 *
 * Fetches a real photo from CarsXE API by make/model/year/color.
 * Falls back to an embedded car photo if API key not set or call fails.
 */
import React, { useState, useEffect } from 'react';
import { Image, View, ActivityIndicator, StyleSheet } from 'react-native';
import { Colors } from '../../constants';

type CarType = 'sedan' | 'suv' | 'luxury';

interface Props {
  make?:     string;
  model?:    string;
  year?:     string | number;
  color?:    string;
  colorHex?: string;
  type?:     CarType;
  width?:    number;
  height?:   number;
}

// Fallback car photo (2022 Toyota Camry, Pearl White) — shown when CarsXE unavailable
const FALLBACK_CAR = 'data:image/png;base64,';

export default function CarIllustration({
  make, model, year, color,
  width = 280, height = 160,
}: Props) {
  const [uri, setUri] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    const key = process.env.EXPO_PUBLIC_CARSXE_KEY;
    if (!key || !make) {
      setUri(FALLBACK_CAR);
      return;
    }

    setLoading(true);
    const params = new URLSearchParams({
      key,
      make:  make  || '',
      model: model || '',
      year:  String(year || ''),
      color: color || '',
      angle: '32',
    });

    fetch(`https://api.carsxe.com/images?${params}`)
      .then(r => r.json())
      .then(data => {
        const url = data?.images?.[0]?.url;
        setUri(url || FALLBACK_CAR);
      })
      .catch(() => setUri(FALLBACK_CAR))
      .finally(() => setLoading(false));
  }, [make, model, year, color]);

  return (
    <View style={{ width, height, alignItems: 'center', justifyContent: 'center' }}>
      {loading && (
        <ActivityIndicator color={Colors.brand} size="small" style={StyleSheet.absoluteFill} />
      )}
      {uri && (
        <Image
          source={{ uri }}
          style={{ width, height, resizeMode: 'contain' }}
          onError={() => setUri(FALLBACK_CAR)}
        />
      )}
    </View>
  );
}
